public class DecoratorPattern {
    interface Coffee { int cost(); String desc(); }
    static class Basic implements Coffee {
        public int cost() { return 5; }
        public String desc() { return "basic"; }
    }
    static class Milk implements Coffee {
        Coffee c; Milk(Coffee c) { this.c = c; }
        public int cost() { return c.cost() + 2; }
        public String desc() { return c.desc() + "+milk"; }
    }
    static class Sugar implements Coffee {
        Coffee c; Sugar(Coffee c) { this.c = c; }
        public int cost() { return c.cost() + 1; }
        public String desc() { return c.desc() + "+sugar"; }
    }
    public static void main(String[] args) {
        Coffee c = new Sugar(new Milk(new Basic()));
        System.out.println(c.cost());
        System.out.println(c.desc());
    }
}
